def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            penalty = (ratio - 1) ** 3
            priorities[i] = penalty * 100
        elif 0.5 < ratio <= 1:
            priorities[i] = 1 / (1 + np.exp(-10 * (ratio - 0.75)))
        else:
            score = 0
            for j in range(1, 5):
                score += ((ratio * j) ** 2) / j
            priorities[i] = 1 / (1 + score)
        if capacity % 2 == 0:
            priorities[i] *= 1.1
        else:
            priorities[i] *= 0.9
    return priorities
